{
  "categories": [
    {
      "category_id": "audio-datasets",
      "name": "Audio Datasets",
      "short_description": "Collection, curation, ground-truth annotation, and DVC versioning of production audio used for STT experiments.",
      "detailed_description": "Covers tasks that source, clean, and version audio data from Rezolve production sessions. This includes mining production logs for voice clips, annotating ground-truth transcripts, tagging entity spans and utterance categories, and managing large audio files via DVC against the Azure Blob remote. The gold-92 benchmark dataset belongs to this category. Tasks here produce the data assets consumed by stt-evaluation, entity-correction, and whisper-finetuning tasks.",
      "version": 1
    },
    {
      "category_id": "commercial-apis",
      "name": "Commercial APIs",
      "short_description": "Integration and evaluation of third-party STT APIs, primarily Deepgram Nova-2, as the production baseline.",
      "detailed_description": "Covers tasks that call, configure, and measure commercial speech-to-text services. The main subject is Deepgram Nova-2, which is the current Rezolve production STT endpoint. Work in this category establishes the baseline accuracy and latency numbers that all open-source and fine-tuned approaches are compared against. It may also include evaluation of other commercial options (e.g., Azure Speech, Google STT) if they become relevant to the research roadmap.",
      "version": 1
    },
    {
      "category_id": "confidence-routing",
      "name": "Confidence Routing",
      "short_description": "Threshold-based decision logic that routes each utterance to accept, correct, clarify, or fallback based on ASR confidence.",
      "detailed_description": "Covers tasks that design and evaluate policies for acting on STT output with varying reliability. A routing policy maps confidence scores (and optionally entity-level scores) to one of four outcomes: accept the transcript, apply post-correction, ask the user for clarification, or hand off to a fallback path. The key objectives are keeping the wrong-confident-action rate below 2% and the clarification rate below 5% on the gold-92 benchmark without sacrificing throughput.",
      "version": 1
    },
    {
      "category_id": "entity-correction",
      "name": "Entity Correction",
      "short_description": "Post-correction strategies that improve accuracy on domain-specific entities after the raw ASR transcript is produced.",
      "detailed_description": "Covers work that takes a raw ASR transcript and applies a correction pass to fix brand names, product lines, SKUs, and other Rezolve-specific entities. Techniques include LLM correction passes, custom vocabulary injection, and contextual entity boosting. Tasks here focus on accuracy gains measured on action-critical spans of the gold-92 benchmark and on the incremental latency cost each approach adds to the voice-to-action pipeline.",
      "version": 1
    },
    {
      "category_id": "latency-profiling",
      "name": "Latency Profiling",
      "short_description": "End-to-end measurement of voice-to-action latency from speech end to tool call across candidate STT pipeline configurations.",
      "detailed_description": "Covers tasks that instrument and measure the full latency path: speech capture end, ASR decoding, optional post-correction, confidence routing, and downstream tool call dispatch. The success threshold is p50 < 800 ms. Tasks here profile individual stages, compare latency across candidate systems, and identify bottlenecks. Latency data is collected alongside accuracy metrics so accuracy–latency trade-offs can be reasoned about explicitly.",
      "version": 1
    },
    {
      "category_id": "stt-evaluation",
      "name": "STT Evaluation",
      "short_description": "Benchmarking ASR systems on entity accuracy, WER, and intent preservation using the gold-92 held-out set.",
      "detailed_description": "Covers tasks that measure how well a speech-to-text system transcribes Rezolve production audio. Primary metrics are entity accuracy on action-critical spans, word error rate, and intent preservation, evaluated against the gold-92 benchmark. This category includes initial baseline runs, cross-system comparisons, and regression checks. It does not include tasks that modify the STT pipeline itself — see entity-correction, confidence-routing, and whisper-finetuning for those.",
      "version": 1
    },
    {
      "category_id": "whisper-finetuning",
      "name": "Whisper Fine-Tuning",
      "short_description": "Domain-adapted fine-tuning of Whisper-class ASR models on Rezolve production audio to improve entity accuracy.",
      "detailed_description": "Covers experiments that adapt pre-trained Whisper (or Whisper-derived) models to the Rezolve voice commerce domain. Tasks include dataset preparation from production audio, supervised fine-tuning runs, hyperparameter sweeps, and post-fine-tune evaluation on the gold-92 benchmark. A key constraint is that fine-tuned models must not regress general English WER relative to the base checkpoint. Gold-92 is never used for training — only for held-out evaluation.",
      "version": 1
    }
  ]
}

